String buildPriceLine() {
    java.util.concurrent.CompletableFuture<Integer> priceF =
        java.util.concurrent.CompletableFuture.supplyAsync(() -> 100, pool)
            .exceptionally(ex -> 0);

    java.util.concurrent.CompletableFuture<Integer> discountF =
        java.util.concurrent.CompletableFuture.supplyAsync(() -> 15, pool)
            .exceptionally(ex -> 0);

    return priceF.thenCombine(discountF, (price, discount) -> {
        int finalPrice = price - discount;
        return "finalPrice=" + finalPrice;
    }).join();
}

